            groups[key].append(row)

    result = []
    for key, rows in groups.items():
        # Sort rows by the 4th column (variant name) to ensure consistent ordering
        rows.sort(key=lambda r: r[3] if r[3] else "")

        # Find the last row in the group that has a date in the 5th column
        # or a total count in the 7th column that is non-empty.
        candidates = []
        for r in rows:
            # Check if 5th column (index 4) has a date-like string or 7th column (index 6) has a count
            if r[4] and (r[4].replace("-", "").isdigit() or r[4].isdigit()):
                 candidates.append(r)
            elif r[6] and r[6].isdigit():
                 candidates.append(r)

        if candidates:
            # Sort candidates by the 5th column (date) to pick the latest one if multiple exist
            # or by the 7th column (count) if dates are missing.
            # The example shows only one row with the date/total.
            # We'll pick the one with the latest date if available, otherwise the one with the highest count.
            def sort_key(c):
                d = c[4] if c[4] else ""
                c_val = c[6] if c[6] else 0
                # Try to parse date to sort
                try:
                    if d:
                        # Simple date parsing for YYYY-MM-DD or MM/DD/YYYY
                        # The example has 11/5/2007 (MM/DD/YYYY)
                        parts = d.split('/')
                        if len(parts) == 3:
                            # Assume MM/DD/YYYY format based on examples
                            m, d, y = parts
                            return (int(y), int(m), int(d))
                except:
                    pass
                return (0, 0, 0)

            candidates.sort(key=sort_key)
            result.append(candidates[-1])
        else:
            # If no candidates found, just take the last row in the group
            result.append(rows[-1])

    return result

